package com.infy.inventrack.inventory.config; import com.infy.inventrack.inventory.entity.InventoryItem; import com.infy.inventrack.inventory.repository.InventoryRepository; import org.springframework.boot.CommandLineRunner; import org.springframework.context.annotation.*; import java.math.BigDecimal; @Configuration public class DataSeeder { @Bean CommandLineRunner seedInventory(InventoryRepository r){ return args->{ if(!r.existsBySku("SKU12300")){ InventoryItem i=new InventoryItem(); i.setSku("SKU12300"); i.setStockQuantity(50); i.setUnitPrice(new BigDecimal("88999.00")); r.save(i); } }; } }
